import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"20. Casual Conversion","description":"","frontmatter":{"title":"20. Casual Conversion","eba":"Doctors in Training 2022-2026","topics":["employment","casual-conversion"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/20-casual-conversion.md","filePath":"ebas/doctors-in-training/doctor-employment/20-casual-conversion.md"}'),n={name:"ebas/doctors-in-training/doctor-employment/20-casual-conversion.md"};function i(a,e,h,c,p,g){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_20-casual-conversion" tabindex="-1">20. Casual Conversion <a class="header-anchor" href="#_20-casual-conversion" aria-label="Permalink to &quot;20. Casual Conversion&quot;">​</a></h1><p><strong>20.1</strong> Health Service offers</p><p><strong>(a)</strong> Subject to subclause 20.12 and by 27 September 2021 in accordance with the NES, an Employer must make an offer to a Doctor under this section if:</p><p><strong>(i)</strong> the Doctor has worked shifts for the Health Service for a period of 12 months beginning the day the employment started; and</p><p><strong>(ii)</strong> during at least the last 6 months of that period, the Doctor has worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Doctor could continue to work as a full-time Doctor or a</p><p><strong>(b)</strong> The Health Service’s offer under subclause 20.1 must:</p><p><strong>(i)</strong> be in writing; and</p><p><strong>(ii)</strong> be an offer for the Doctor to convert:</p><p>A. for a Doctor that has worked the equivalent of full-time hours during the period referred to in subclause 201.1(a)(ii) – to full- time employment; or</p><p>B. for a Doctor that has worked less than the equivalent of full- time hours during the period referred to in subclause 20.1 – to pattern of hours worked during that period;</p><p><strong>(iii)</strong> be given to the Doctor within 21 days after the end of the 12-month period referred to in <a href="/eba/ebas/doctors-in-training/doctor-employment/21-period-of-employment.html">clause 21.1</a>(a)(i).</p><p><strong>20.2</strong> When Health Service offers not required</p><p><strong>(a)</strong> A Health Service is not required to make an offer under subclause 20.1(a) to a Doctor if:</p><p><strong>(i)</strong> there are reasonable grounds not to make that offer; and</p><p><strong>(ii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of deciding not to make the offer;</p><p><strong>(b)</strong> The Health Service must give written notice to a Doctor in accordance with clause 1.1(d) if:</p><p><strong>(i)</strong> the Health Service decides under clause 20.2(a) not to make an offer to the Doctor; or</p><p><strong>(ii)</strong> the Doctor has been employed by the Health Service for the 12-month period referred to in subclause 20.1(a)(i) but does not meet the requirement referred to in subclause 1.1(a)(ii).</p><p><strong>(c)</strong> Without limiting subclause 20.2, reasonable grounds for deciding not to make an offer include the following:</p><p><strong>(i)</strong> the Doctor&#39;s position will cease to exist in the period of 12 months after the time of deciding not to make the offer, such as where a Doctor works shifts replacing an employee absence;</p><p><strong>(ii)</strong> the hours of work which the Doctor is required to perform will be significantly reduced in that period;</p><p><strong>(iii)</strong> there will be a significant change in either or both of the following in that period:</p><p>A. the days on which the Doctor’s hours of work are required to be performed;</p><p>B. the times at which the Doctor&#39;s hours of work are required to be performed;</p><p>which cannot be accommodated within the days or times the Doctor is available to work during that period;</p><p><strong>(iv)</strong> making the offer would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>(d)</strong> The notice must:</p><p><strong>(i)</strong> advise the Doctor that the Health Service is not making an offer under subclause 20.1; and</p><p><strong>(ii)</strong> include the details of the reasons for not making the offer (including any grounds on which the Health Service has decided to not make the offer); and</p><p><strong>(iii)</strong> be given to the Doctor within 21 days after the end of the 12-month period referred to in subclause 1.1(a)(i).</p><p><strong>20.3</strong> Doctor response</p><p><strong>(a)</strong> The Doctor must give the Health Service a written response to the offer made under 20.1(a) within 21 days after the offer is given to the Doctor, stating whether the Doctor accepts or declines the offer.</p><p><strong>(b)</strong> If the Doctor fails to give the Health Service a written response in accordance with subclause 1.1(a), the Doctor is taken to have declined the offer.</p><p><strong>20.4</strong> Acceptances of offers</p><p><strong>(a)</strong> If the Doctor accepts the offer, the Employer must, within 21 days after the day the acceptance is given to the Employer, give written notice to the Doctor of the following:</p><p><strong>(i)</strong> whether the Doctor is converting to full-time employment of part-time employment;</p><p><strong>(ii)</strong> the Doctor&#39;s hours of work after the conversion takes effect;</p><p><strong>(iii)</strong> the day the Doctor&#39;s conversion to full-time or part-time employment takes effect</p><p><strong>(b)</strong> However, the Health Service must discuss with the Doctor the matters the Health Service intends to specify for the purposes of subclause 1.1(a)(i)-(iii) before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 1.1(a)(iii) must be the first day of the Doctors’ first full pay period that starts after the day the notice is given, unless the Doctor and Health Service agree to another day.</p><p><strong>20.5</strong> Doctor requests</p><p><strong>(a)</strong> A Doctor may make a request of a Health Service under this clause if:</p><p><strong>(i)</strong> the Doctor has been employed by the Health Service for a period of at least 6 months beginning the day the employment started;</p><p><strong>(ii)</strong> the Doctor has, in the period of 6 months ending the day the request is given, worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Doctor could continue to work as a full-time Doctor or part-time Doctor (as the case may be); and</p><p><strong>(iii)</strong> all of the following apply:</p><p><strong>(A)</strong> the Doctor has not, at any time during the period referred to in subclause 21.1(a)(ii), refused an offer made to the Doctor under clause 20.1;</p><p><strong>(B)</strong> the Health Service has not, at any time during that period, given the Doctor a notice in accordance with subclause 21.1(c)(i);</p><p><strong>(C)</strong> the Health Service has not, at any time during that period, given a response to the Doctor under subclause 20.6 refusing a previous request made under this clause;</p><p><strong>(D)</strong> the request is not made during the period of 21 days after the period referred to in subclause 20.1(a)(i).</p><p><strong>(b)</strong> The request must:</p><p><strong>(i)</strong> be in writing;</p><p><strong>(ii)</strong> be a request for the Doctor to convert:</p><p><strong>(A)</strong> for a Doctor that has worked the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 20.51.1(a)(ii) – to full-time employment; or</p><p><strong>(B)</strong> for a Doctor that has worked less than the equivalent of full- time hours or shifts on a regular and systematic basis during the period referred to in subclause 20.5(a)(ii) – to part-time employment that is consistent with the regular pattern of hours or shifts worked during that period; and</p><p><strong>(iii)</strong> be given to the Health Service.</p><p><strong>20.6</strong> Health Service must give a response</p><p>The Health Service must give the Doctor a written response to the request made under subclause 20.5 within 21 days after the request is given to the Health Service, stating whether the Health Service grants or refuses the request.</p><p><strong>20.7</strong> Refusals of requests</p><p><strong>(a)</strong> The Health Service must not refuse the request unless:</p><p><strong>(i)</strong> the Health Service has consulted the Doctor;</p><p><strong>(ii)</strong> there are reasonable grounds the refuse the request; and</p><p><strong>(iii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of refusing the request.</p><p><strong>(b)</strong> Without limiting subclause 20.71.1(a), reasonable grounds for refusing a request include the following:</p><p><strong>(i)</strong> it would require a significant adjustment to the Doctor’s hours of work in order for the Doctor to be employed as a full-time Doctor or part-time Doctor;</p><p><strong>(ii)</strong> the Doctor’s position will cease to exist in the period of 12 months after giving the request;</p><p><strong>(iii)</strong> the hours of work which the Doctor is required to perform will be significantly reduced in the period of 12 months after giving the request;</p><p><strong>(iv)</strong> there will be a significant change in either or both of the following in the period of 12 months after giving the request:</p><p><strong>(A)</strong> the days on which the Doctor’s hours of work are required to be performed;</p><p><strong>(B)</strong> the times at which the Doctor’s hours of work are required to be performed;</p><p>which cannot be accommodated within the days or times the Doctor is available to work during that period;</p><p><strong>(v)</strong> granting the request would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory</p><p><strong>(c)</strong> If the Health Service refuses the request, the written response under subclause</p><p><strong>20.6</strong> must include details of the reasons for the refusal.</p><p><strong>20.8</strong> Grants of requests</p><p><strong>(a)</strong> If the Employer grants the request, the Employer must, within 21 days after the day the request is given to the Employer, give written notice to the Employee of the following:</p><p><strong>(i)</strong> whether the Doctor is converting to full-time employment of part-time employment;</p><p><strong>(ii)</strong> the Doctor&#39;s pattern of hours or shifts after the conversion takes effect;</p><p><strong>(iii)</strong> the day the Doctor&#39;s conversion to full-time or part-time employment takes effect</p><p><strong>(b)</strong> However, the Employer must discuss with the Doctor the matters the Health Service intends to specify for the purposes of subclauses 20.81.1(a)(i)-(iii) before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 20.8(a)(iii)1.1(a)(iii) must be the first day of the Doctor&#39;s first full pay period that starts after the day the notice is given, unless the Doctor and Health Service agree to another day.</p><p><strong>(d)</strong> To avoid doubt, the notice may be included in the written response under subclause 20.6.</p><p><strong>20.9</strong> Effect of conversion</p><p><strong>(a)</strong> A Doctor is taken, on and after the day specified in a notice for the purposes of subclauses 20.4(a)(iii) and 20.8(a)(iii) to be a full-time Doctor or a part-time Doctor of the Health Service.</p><p><strong>(b)</strong> Casual loading will cease, and, subject to subclause 20.6, any benefits relating to permanent employment will commence on the day specified in a notice for the purposes of subclauses 20.4(a)(iii) and 20.8(a)(iii).</p><p>Plain language terms: casual to permanent.</p>',85)])])}const f=t(n,[["render",i]]);export{l as __pageData,f as default};
